'use server'

import { prisma } from '@/lib/prisma'
import { revalidatePath } from 'next/cache'
import { getIronSession } from 'iron-session'
import { cookies } from 'next/headers'
import { sessionOptions, SessionData } from '@/lib/session'

export async function updateBudgetEntry(
    tenantId: string,
    accountId: string,
    month: number,
    year: number,
    year: number,
    amount: number,
    budgetVersionId: string,
    dimensions: {
        companyId: string
        costCenterId?: string | null
        clientId?: string | null
    }
) {
    // 1. Auth Check
    const session = await getIronSession<SessionData>(await cookies(), sessionOptions)
    if (!session.isLoggedIn || session.tenantId !== tenantId) {
        throw new Error('Unauthorized')
    }

    // 2. Permission Check
    // If user is ADMIN, allow all. validation
    // If user is USER, check specific permission for Company and CostCenter
    if (session.role !== 'ADMIN') {
        const userPermissions = await prisma.userPermission.findMany({
            where: { userId: session.userId }
        })

        // Check Company Permission
        // If user has NO company permissions, maybe they are allowed none? Or all? 
        // Logic: If list is empty, default to DENY? Or if they have a permission entry, it restricts?
        // Let's assume: If you have permissions in table, you are restricted to those. If table empty? 
        // Based on Seed, we created permissions for Restricted user.
        // Let's implement: If you have "Company Permission" entries, you must match one.

        const companyPerms = userPermissions.filter(p => p.companyId)
        if (companyPerms.length > 0) {
            const hasAccess = companyPerms.some(p => p.companyId === dimensions.companyId)
            if (!hasAccess) {
                throw new Error('Forbidden: No access to this Company')
            }
        }

        // Check CostCenter Permission
        if (dimensions.costCenterId) {
            const ccPerms = userPermissions.filter(p => p.costCenterId)
            if (ccPerms.length > 0) {
                const hasAccess = ccPerms.some(p => p.costCenterId === dimensions.costCenterId)
                if (!hasAccess) {
                    throw new Error('Forbidden: No access to this Cost Center')
                }
            }
        }
    }
    const existing = await prisma.budgetEntry.findFirst({
        where: {
            tenantId,
            accountId,
            month,
            year,
            companyId: dimensions.companyId,
            // Simplifying match logic for MVP: just company for now to test basics
            // In real app, we need to match ALL undefined/defined dimensions
        }
    })

    if (existing) {
        if (amount === 0) {
            await prisma.budgetEntry.delete({ where: { id: existing.id } })
        } else {
            await prisma.budgetEntry.update({
                where: { id: existing.id },
                data: { amount }
            })
        }
    } else {
        if (amount !== 0) {
            await prisma.budgetEntry.create({
                data: {
                    tenantId,
                    accountId,
                    month,
                    year,
                    amount,
                    companyId: dimensions.companyId,
                    costCenterId: dimensions.costCenterId,
                    clientId: dimensions.clientId
                }
            })
        }
    }

    revalidatePath('/dashboard/dre')
}

export async function batchUpdateBudgetEntries(
    tenantId: string,
    accountId: string,
    year: number,
    entries: { month: number; amount: number }[],
    dimensions: {
        companyId: string
        costCenterId?: string | null
        clientId?: string | null
    }
) {
    const session = await getIronSession<SessionData>(await cookies(), sessionOptions)
    if (!session.isLoggedIn || session.tenantId !== tenantId) throw new Error('Unauthorized')

    // Permission checks (same as single update - reusing logic would be better but duplicating for MVP speed)
    if (session.role !== 'ADMIN') {
        const userPermissions = await prisma.userPermission.findMany({ where: { userId: session.userId } })

        const companyPerms = userPermissions.filter(p => p.companyId)
        if (companyPerms.length > 0) {
            if (!companyPerms.some(p => p.companyId === dimensions.companyId)) {
                throw new Error('Forbidden: No access to this Company')
            }
        }
        if (dimensions.costCenterId) {
            const ccPerms = userPermissions.filter(p => p.costCenterId)
            if (ccPerms.length > 0 && !ccPerms.some(p => p.costCenterId === dimensions.costCenterId)) {
                throw new Error('Forbidden: No access to this Cost Center')
            }
        }
    }

    // Transaction to ensure atomicity
    await prisma.$transaction(async (tx) => {
        for (const entry of entries) {
            const existing = await tx.budgetEntry.findFirst({
                where: {
                    tenantId,
                    accountId,
                    month: entry.month,
                    year,
                    companyId: dimensions.companyId,
                    costCenterId: dimensions.costCenterId,
                    clientId: dimensions.clientId
                }
            })

            if (existing) {
                if (entry.amount === 0) {
                    await tx.budgetEntry.delete({ where: { id: existing.id } })
                } else {
                    await tx.budgetEntry.update({ where: { id: existing.id }, data: { amount: entry.amount } })
                }
            } else if (entry.amount !== 0) {
                await tx.budgetEntry.create({
                    data: {
                        tenantId,
                        accountId,
                        month: entry.month,
                        year,
                        amount: entry.amount,
                        companyId: dimensions.companyId,
                        costCenterId: dimensions.costCenterId,
                        clientId: dimensions.clientId
                    }
                })
            }
        }
    })

    revalidatePath('/dashboard/dre')
}
